_TV_PREFIX_RE = re.compile(r"^tv_(resnet(34|50|101|152)|resnext50_32x4d|densenet121)$")


def _strip_timm_prefix(name: str) -> str:
    return name.split(":", 1)[1] if name.startswith("timm:") else name


def _has_pretrained(name: str) -> bool:
    return name in _PRETRAINED


def _exposed(name: str) -> bool:
    return hasattr(timm.models, name)


def _tv_alias(name: str) -> str | None:
    m = _TV_PREFIX_RE.match(name)
    if not m:
        return None
    base = name.removeprefix("tv_")
    return {
        "densenet121": "densenet121",
        "resnet34": "resnet34",
        "resnet50": "resnet50",
        "resnet101": "resnet101",
        "resnet152": "resnet152",
        "resnext50_32x4d": "resnext50_32x4d",
    }.get(base, base)


def _ctor_from_timm(name: str, is_tv: bool = False):
    def ctor(*args, **kwargs):
        return timm.create_model(name, *args, **kwargs)

    ctor.__is_timm_tv__ = is_tv
    ctor.__name__ = name
    ctor.__module__ = f"timm.models.{name}"
    return ctor


def get_timm_backbone_fn(bckbn: str):
    orig = _strip_timm_prefix(bckbn)

    if _exposed(orig) and _has_pretrained(orig):
        return getattr(timm.models, orig)

    tv = _tv_alias(orig)
    if tv and _has_pretrained(tv):
        if _exposed(tv):
            tv_module = getattr(timm.models, tv)
            tv_module.__is_timm_tv__ = True
            return tv_module
        return _ctor_from_timm(tv, is_tv=True)

    if orig in TIMM_MODEL_NAME_MAP:
        mapped = TIMM_MODEL_NAME_MAP[orig]
        if _has_pretrained(mapped):
            if _exposed(mapped):

                def ctor(*args, **kwargs):
                    return timm.create_model(mapped, *args, **kwargs)

                ctor.__name__ = orig
                ctor.__module__ = f"timm.models.{mapped}"
                return ctor

            return _ctor_from_timm(mapped)

    if orig in TIMM_MODEL_HUB_MAP:
        repo, entry = TIMM_MODEL_HUB_MAP[orig]

        def ctor(*args, **kwargs):
            kwargs.pop("pretrained", None)
            return torch.hub.load(repo, entry, *args, **kwargs)

        ctor.__name__ = orig
        ctor.__is_timm_legacy__ = True
        ctor.__module__ = f"torch.hub.{repo.replace('/','_')}.{entry}"
        return ctor

    if _has_pretrained(orig):
        return _ctor_from_timm(orig)

    raise AttributeError(
        f"Unknown/unsupported backbone for timm==1.x with pretrained weights: {bckbn!r}"
    )
